    pub label: Option<String>,
}

impl WorkerTask {
    /// Creates a worker task from an id and work kind.
    pub fn new(id: impl Into<WorkerTaskId>, kind: WorkerTaskKind) -> Self {
        Self {
            id: id.into(),
            kind,
            label: None,
        }
    }

