    app.on_about_copy_label_reset_requested({
        let app = app.as_weak();
        let controller = Arc::clone(&controller);

        move |action_id| {
            let action_id = action_id.to_string();
            let Some(app) = app.upgrade() else {
                tracing::warn!(
                    event = "s05-about-copy-label-reset-dropped",
