        ActionRejectionKind::WorkerUnavailable,
        ABOUT_ACTION_START_ERROR,
        Some(error.to_string()),
    )
}

fn about_action_matches_callback(action: AboutActionKind, callback_kind: AboutCallbackKind) -> bool {
