        (action, callback_kind),
        (AboutActionKind::Open { .. }, AboutCallbackKind::Open)
            | (AboutActionKind::Copy { .. }, AboutCallbackKind::Copy)
    )
}

fn about_callback_mismatch_feedback(
    action_id: &str,
