fn bind_tools_worker_sink(
    app: &MainWindow,
    controller: Arc<Mutex<ToolsController>>,
) -> SlintEventLoopSink {
    let app = app.as_weak();
    SlintEventLoopSink::new(move |event| {
        let task_id = event.task.id.to_string();
